// Workflow JavaScript Action — 30min BizEvents injector for CoreWeave GPU Cloud KPI Demo
// Requirements:
//   - Workflow must run in Dynatrace Platform context (AutomationEngine)
//   - Uses integrated authentication (no token required)
// References: Dynatrace Business Events API v2 with platform-native fetch.

export default async function () {
  // ---------- Tunables (per 30-min run) ----------
  const HOURS_WINDOW       = 0.5;    // 30 minutes per run
  const CHUNK              = 500;    // keep requests well under ~5MB

  // KPI 1: GPU Infrastructure
  const GPU_NODE_MIN       = 250;
  const GPU_NODE_MAX       = 400;    // GPU node status events per run
  const GPU_ACTIVE_RATE    = 0.985;  // ~98.5% active
  const GPU_DEGRADED_RATE  = 0.010;  // ~1.0% degraded
  const GPU_DISCOVERY_SUCCESS = 0.992; // ~99.2% auto-discovery success

  // KPI 2: AI/ML & LLM Inference
  const LLM_INFERENCE_MIN  = 400;
  const LLM_INFERENCE_MAX  = 800;    // inference requests per run
  const LLM_ERROR_RATE     = 0.015;  // ~1.5% failure rate

  // KPI 3: Proactive Operations
  const ANOMALY_MIN        = 8;
  const ANOMALY_MAX        = 20;     // anomalies detected per run
  const AUTO_REMEDIATION_RATE = 0.82; // ~82% auto-remediated

  // KPI 4: Multi-Cloud Signals
  const CLOUD_SIGNAL_MIN   = 80;
  const CLOUD_SIGNAL_MAX   = 200;    // observability signals per run

  // KPI 5: Cost Optimization
  const COST_METRIC_COUNT  = 7;      // one per cluster

  // KPI 6: Security Posture
  const SECURITY_SCAN_MIN  = 5;
  const SECURITY_SCAN_MAX  = 10;
  const VULN_DETECT_MIN    = 3;
  const VULN_DETECT_MAX    = 12;
  const VULN_REMEDIATE_RATE = 0.75;  // 75% auto-remediated

  // KPI 7: Autonomous Operations
  const AGENT_ACTION_MIN   = 12;
  const AGENT_ACTION_MAX   = 35;
  const AGENT_SUCCESS_RATE = 0.96;   // 96% success

  // ---------- Demo catalogs ----------
  const EVENT_PROVIDER = "coreweave.event.provider";

  // CoreWeave cluster locations (based on real data center regions)
  const CLUSTERS = ["ORD1", "LGA1", "LAS1", "EWR2", "PHX1", "SJC1", "DFW1"];
  const CLUSTER_WEIGHTS = [0.25, 0.20, 0.15, 0.12, 0.10, 0.10, 0.08];

  // Cluster geographic coordinates (real CoreWeave data center locations)
  const CLUSTER_COORDS = {
    "ORD1": { lat: 41.8781, lon: -87.6298 },   // Chicago, IL
    "LGA1": { lat: 40.7769, lon: -73.8740 },   // New York, NY
    "LAS1": { lat: 36.1699, lon: -115.1398 },  // Las Vegas, NV
    "EWR2": { lat: 40.6895, lon: -74.1745 },   // Newark, NJ
    "PHX1": { lat: 33.4484, lon: -112.0740 },  // Phoenix, AZ
    "SJC1": { lat: 37.3382, lon: -121.8863 },  // San Jose, CA
    "DFW1": { lat: 32.7767, lon: -96.7970 }    // Dallas, TX
  };

  // GPU accelerator types CoreWeave offers
  const GPU_TYPES = ["NVIDIA_H100_SXM", "NVIDIA_H200", "NVIDIA_A100_80GB", "NVIDIA_L40S", "NVIDIA_A6000", "NVIDIA_H100_NVL"];
  const GPU_WEIGHTS = [0.30, 0.15, 0.20, 0.15, 0.10, 0.10];

  // LLM / AI Models commonly run on CoreWeave
  const MODELS = ["Llama-3-70B", "Mistral-Large", "Stable-Diffusion-XL", "Whisper-Large-v3", "CodeLlama-34B", "DBRX-Instruct"];
  const MODEL_WEIGHTS = [0.30, 0.20, 0.15, 0.12, 0.13, 0.10];

  // Cloud providers for multi-cloud signal distribution
  const CLOUD_PROVIDERS = ["CoreWeave", "AWS", "Azure", "GCP"];
  const CLOUD_WEIGHTS = [0.45, 0.25, 0.18, 0.12];

  // Signal types for multi-cloud observability
  const SIGNAL_TYPES = ["metrics", "traces", "logs", "events", "topology"];
  const SIGNAL_WEIGHTS = [0.30, 0.25, 0.25, 0.12, 0.08];

  // Anomaly types
  const ANOMALY_TYPES = ["gpu_thermal", "memory_leak", "latency_spike", "node_unreachable", "disk_pressure", "network_degradation", "oom_kill"];
  const ANOMALY_WEIGHTS = [0.20, 0.15, 0.20, 0.12, 0.10, 0.13, 0.10];

  // Anomaly severity levels
  const ANOMALY_SEVERITIES = ["critical", "high", "medium", "low"];
  const SEVERITY_WEIGHTS = [0.10, 0.25, 0.40, 0.25];

  // Compliance frameworks
  const COMPLIANCE_FRAMEWORKS = ["SOC2", "ISO27001", "HIPAA", "PCI-DSS", "FedRAMP"];
  const COMPLIANCE_WEIGHTS = [0.30, 0.25, 0.15, 0.15, 0.15];

  // Vulnerability severity levels
  const VULN_SEVERITIES = ["critical", "high", "medium", "low"];
  const VULN_SEVERITY_WEIGHTS = [0.05, 0.15, 0.45, 0.35];

  // Intelligence Agent action types
  const AGENT_ACTIONS = ["auto_scale_gpu", "drain_node", "restart_pod", "rebalance_workload", "update_config", "isolate_node", "trigger_failover"];
  const AGENT_ACTION_WEIGHTS = [0.25, 0.12, 0.20, 0.15, 0.10, 0.08, 0.10];

  // Kubernetes namespaces (typical CoreWeave tenant workloads)
  const NAMESPACES = ["ml-training", "inference-prod", "inference-staging", "batch-jobs", "data-pipeline", "model-serving"];

  // ---------- Helpers ----------
  function nowUtc() { return new Date(); }
  function toIso(d) { return new Date(d).toISOString(); }
  function clampFuture(ts, now, safetySeconds) {
    const maxAllowed = new Date(now.getTime() - (safetySeconds * 1000));
    return ts > maxAllowed ? maxAllowed : ts;
  }
  function randInt(min, max) { return Math.floor(Math.random() * (max - min + 1)) + min; }
  function randFloat(min, max) { return (Math.random() * (max - min)) + min; }
  function choose(arr) { return arr[Math.floor(Math.random() * arr.length)]; }
  function chooseWeighted(options, weights) {
    const total = weights.reduce((a, b) => a + b, 0);
    const w = weights.map(v => v / (total || 1));
    const r = Math.random();
    let acc = 0;
    for (let i = 0; i < options.length; i++) {
      acc += w[i];
      if (r <= acc) return options[i];
    }
    return options[options.length - 1];
  }
  function distribute(start, end, count, jitter) {
    const spanMs = end.getTime() - start.getTime();
    const stepMs = Math.max(1, Math.floor(spanMs / Math.max(1, count)));
    const out = [];
    for (let i = 0; i < count; i++) {
      const base = new Date(start.getTime() + (i * stepMs));
      const jms = Math.floor(((Math.random() * 2 * jitter) - jitter) * stepMs);
      out.push(new Date(base.getTime() + jms));
    }
    return out;
  }
  function makeEvent(provider, etype, ts, extra, now) {
    const safeTs = clampFuture(ts, now, 30);
    const ev = { "event.provider": provider, "event.type": etype, "timestamp": toIso(safeTs) };
    if (extra && typeof extra === "object") Object.assign(ev, extra);
    return ev;
  }
  function countBy(arr, fn) {
    const m = {};
    for (let i = 0; i < arr.length; i++) {
      const k = fn(arr[i]);
      m[k] = (m[k] || 0) + 1;
    }
    return m;
  }
  function startPlus(dt, minutes) { return new Date(dt.getTime() + (minutes * 60000)); }
  function endMinus(dt, minutes) { return new Date(dt.getTime() - (minutes * 60000)); }
  function cryptoRandomId(len) {
    const hex = "abcdef0123456789";
    let out = "";
    for (let i = 0; i < len; i++) { out += hex[Math.floor(Math.random() * hex.length)]; }
    return out.toUpperCase();
  }

  // ---------- Generate events for the time window ----------
  const now = nowUtc();
  const start = new Date(now.getTime() - (HOURS_WINDOW * 3600000));
  const events = [];

  // =========================================================================
  // KPI 1: GPU Infrastructure Observability
  // Dynatrace OneAgent auto-discovers GPU nodes with zero configuration.
  // =========================================================================
  const GPU_NODE_COUNT = randInt(GPU_NODE_MIN, GPU_NODE_MAX);
  const gpuTimes = distribute(startPlus(start, 1), endMinus(now, 1), GPU_NODE_COUNT, 0.05);

  for (let i = 0; i < gpuTimes.length; i++) {
    const ts = gpuTimes[i];
    const cluster = chooseWeighted(CLUSTERS, CLUSTER_WEIGHTS);
    const gpuType = chooseWeighted(GPU_TYPES, GPU_WEIGHTS);
    const nodeId = "node-" + cluster.toLowerCase() + "-" + cryptoRandomId(6);

    // Determine node status based on configured rates
    const statusRoll = Math.random();
    let nodeStatus = "active";
    if (statusRoll > GPU_ACTIVE_RATE + GPU_DEGRADED_RATE) {
      nodeStatus = "offline";
    } else if (statusRoll > GPU_ACTIVE_RATE) {
      nodeStatus = "degraded";
    }

    // Discovery status
    const discoverySuccess = Math.random() < GPU_DISCOVERY_SUCCESS;

    events.push(makeEvent(EVENT_PROVIDER, "gpu.node.status", ts, {
      "node.id": nodeId,
      "cluster": cluster,
      "gpu.type": gpuType,
      "node.status": nodeStatus,
      "gpu.utilization": nodeStatus === "active" ? Number(randFloat(55, 98).toFixed(1)) : (nodeStatus === "degraded" ? Number(randFloat(10, 45).toFixed(1)) : 0),
      "gpu.memory.used.gb": nodeStatus === "active" ? Number(randFloat(40, 78).toFixed(1)) : 0,
      "gpu.temperature.celsius": nodeStatus === "active" ? randInt(55, 82) : (nodeStatus === "degraded" ? randInt(83, 95) : 0),
      "discovery.status": discoverySuccess ? "success" : "failed",
      "k8s.namespace": choose(NAMESPACES),
      "geo.location.latitude": CLUSTER_COORDS[cluster].lat,
      "geo.location.longitude": CLUSTER_COORDS[cluster].lon
    }, now));
  }

  // =========================================================================
  // KPI 2: AI/ML Workload & LLM Observability
  // Best-in-class observability for GenAI, LLMs, and AI agents.
  // =========================================================================
  const LLM_COUNT = randInt(LLM_INFERENCE_MIN, LLM_INFERENCE_MAX);
  const llmTimes = distribute(startPlus(start, 1), endMinus(now, 1), LLM_COUNT, 0.05);

  for (let i = 0; i < llmTimes.length; i++) {
    const ts = llmTimes[i];
    const cluster = chooseWeighted(CLUSTERS, CLUSTER_WEIGHTS);
    const model = chooseWeighted(MODELS, MODEL_WEIGHTS);
    const isError = Math.random() < LLM_ERROR_RATE;

    const requestId = "REQ-" + cryptoRandomId(10);
    const tokensInput = randInt(50, 4096);
    const tokensOutput = isError ? 0 : randInt(100, 8192);

    // Latency varies by model
    let baseLatency = 0;
    if (model === "Llama-3-70B") baseLatency = randInt(80, 350);
    else if (model === "Mistral-Large") baseLatency = randInt(60, 280);
    else if (model === "Stable-Diffusion-XL") baseLatency = randInt(1500, 6000);
    else if (model === "Whisper-Large-v3") baseLatency = randInt(500, 3000);
    else if (model === "CodeLlama-34B") baseLatency = randInt(70, 300);
    else baseLatency = randInt(100, 400);

    const latency = isError ? randInt(5000, 30000) : baseLatency;

    events.push(makeEvent(EVENT_PROVIDER, isError ? "llm.inference.failed" : "llm.inference.completed", ts, {
      "request.id": requestId,
      "model.name": model,
      "cluster": cluster,
      "tokens.input": tokensInput,
      "tokens.output": tokensOutput,
      "latency.ms": latency,
      "gpu.type": chooseWeighted(GPU_TYPES, GPU_WEIGHTS),
      "k8s.namespace": choose(["inference-prod", "inference-staging", "model-serving"]),
      ...(isError ? { "error.type": choose(["TIMEOUT", "OOM_KILLED", "MODEL_LOAD_FAILURE", "GPU_ERROR", "RATE_LIMITED"]) } : {})
    }, now));
  }

  // =========================================================================
  // KPI 3: Proactive Operations (Anomaly Detection & Auto-Remediation)
  // Davis AI predicts anomalies before they impact users.
  // =========================================================================
  const ANOMALY_COUNT = randInt(ANOMALY_MIN, ANOMALY_MAX);
  const anomalyTimes = distribute(startPlus(start, 2), endMinus(now, 5), ANOMALY_COUNT, 0.1);

  for (let i = 0; i < anomalyTimes.length; i++) {
    const ts = anomalyTimes[i];
    const cluster = chooseWeighted(CLUSTERS, CLUSTER_WEIGHTS);
    const anomalyType = chooseWeighted(ANOMALY_TYPES, ANOMALY_WEIGHTS);
    const severity = chooseWeighted(ANOMALY_SEVERITIES, SEVERITY_WEIGHTS);
    const anomalyId = "ANOM-" + cryptoRandomId(8);

    // Anomaly detected event
    events.push(makeEvent(EVENT_PROVIDER, "anomaly.detected", ts, {
      "anomaly.id": anomalyId,
      "anomaly.type": anomalyType,
      "severity": severity,
      "cluster": cluster,
      "affected.nodes": randInt(1, 8),
      "k8s.namespace": choose(NAMESPACES)
    }, now));

    // Resolution event (1-20 min later)
    const resolutionDelay = randInt(1, 20);
    const resolvedTs = new Date(ts.getTime() + resolutionDelay * 60000);
    if (resolvedTs < now) {
      const isAutoRemediated = Math.random() < AUTO_REMEDIATION_RATE;
      events.push(makeEvent(EVENT_PROVIDER, "anomaly.resolved", resolvedTs, {
        "anomaly.id": anomalyId,
        "anomaly.type": anomalyType,
        "severity": severity,
        "cluster": cluster,
        "resolution.type": isAutoRemediated ? "automated" : "manual",
        "mttr.minutes": resolutionDelay,
        "k8s.namespace": choose(NAMESPACES)
      }, now));
    }
  }

  // =========================================================================
  // KPI 4: Multi-Cloud and Hybrid Visibility
  // Unified observability across CoreWeave + hyperscaler environments.
  // =========================================================================
  const CLOUD_COUNT = randInt(CLOUD_SIGNAL_MIN, CLOUD_SIGNAL_MAX);
  const cloudTimes = distribute(startPlus(start, 1), endMinus(now, 1), CLOUD_COUNT, 0.05);

  for (let i = 0; i < cloudTimes.length; i++) {
    const ts = cloudTimes[i];
    const provider = chooseWeighted(CLOUD_PROVIDERS, CLOUD_WEIGHTS);
    const signalType = chooseWeighted(SIGNAL_TYPES, SIGNAL_WEIGHTS);
    const cluster = chooseWeighted(CLUSTERS, CLUSTER_WEIGHTS);

    events.push(makeEvent(EVENT_PROVIDER, "cloud.observability.signal", ts, {
      "cloud.provider": provider,
      "signal.type": signalType,
      "cluster": cluster,
      "environment": choose(["production", "staging", "development"]),
      "signal.count": randInt(100, 5000),
      "unified.platform": "Dynatrace"
    }, now));
  }

  // =========================================================================
  // KPI 5: Cost Optimization
  // Achieve ~40% lower observability costs, 90% faster MTTR.
  // =========================================================================
  for (let c = 0; c < COST_METRIC_COUNT; c++) {
    const ts = new Date(start.getTime() + randInt(5, 25) * 60000);
    const cluster = CLUSTERS[c % CLUSTERS.length];

    events.push(makeEvent(EVENT_PROVIDER, "cost.optimization.metric", ts, {
      "cluster": cluster,
      "cost.savings.percent": Number(randFloat(32, 48).toFixed(1)),
      "mttr.reduction.percent": Number(randFloat(82, 95).toFixed(1)),
      "platform.availability.percent": Number(randFloat(99.90, 99.99).toFixed(2)),
      "log.cost.reduction.percent": Number(randFloat(35, 50).toFixed(1)),
      "observability.tool.consolidation": randInt(3, 7),
      "cost.category": choose(["compute", "storage", "network", "licensing"])
    }, now));
  }

  // =========================================================================
  // KPI 6: Security Posture Management
  // Continuous monitoring, automated remediation, compliance visibility.
  // =========================================================================
  // Security scans
  const SCAN_COUNT = randInt(SECURITY_SCAN_MIN, SECURITY_SCAN_MAX);
  const scanTimes = distribute(startPlus(start, 2), endMinus(now, 3), SCAN_COUNT, 0.1);

  for (let i = 0; i < scanTimes.length; i++) {
    const ts = scanTimes[i];
    const cluster = chooseWeighted(CLUSTERS, CLUSTER_WEIGHTS);
    const framework = chooseWeighted(COMPLIANCE_FRAMEWORKS, COMPLIANCE_WEIGHTS);

    events.push(makeEvent(EVENT_PROVIDER, "security.scan.completed", ts, {
      "scan.id": "SCAN-" + cryptoRandomId(8),
      "cluster": cluster,
      "compliance.framework": framework,
      "compliance.score": Number(randFloat(88, 99).toFixed(1)),
      "controls.passed": randInt(85, 120),
      "controls.failed": randInt(0, 8),
      "scan.duration.seconds": randInt(30, 300)
    }, now));
  }

  // Vulnerabilities detected
  const VULN_COUNT = randInt(VULN_DETECT_MIN, VULN_DETECT_MAX);
  const vulnTimes = distribute(startPlus(start, 3), endMinus(now, 5), VULN_COUNT, 0.1);

  for (let i = 0; i < vulnTimes.length; i++) {
    const ts = vulnTimes[i];
    const cluster = chooseWeighted(CLUSTERS, CLUSTER_WEIGHTS);
    const severity = chooseWeighted(VULN_SEVERITIES, VULN_SEVERITY_WEIGHTS);
    const vulnId = "CVE-" + (2025 + randInt(0, 1)) + "-" + cryptoRandomId(5);

    events.push(makeEvent(EVENT_PROVIDER, "security.vulnerability.detected", ts, {
      "vulnerability.id": vulnId,
      "vulnerability.severity": severity,
      "cluster": cluster,
      "affected.component": choose(["container-runtime", "k8s-api", "gpu-driver", "base-image", "network-policy", "storage-csi"]),
      "k8s.namespace": choose(NAMESPACES)
    }, now));

    // Remediation (some auto-remediated, 5-15 min later)
    if (Math.random() < VULN_REMEDIATE_RATE) {
      const remediationTs = new Date(ts.getTime() + randInt(5, 15) * 60000);
      if (remediationTs < now) {
        events.push(makeEvent(EVENT_PROVIDER, "security.vulnerability.remediated", remediationTs, {
          "vulnerability.id": vulnId,
          "vulnerability.severity": severity,
          "cluster": cluster,
          "remediation.type": choose(["auto_patch", "config_update", "image_rebuild", "policy_enforcement"]),
          "remediation.time.minutes": Math.round((remediationTs - ts) / 60000)
        }, now));
      }
    }
  }

  // =========================================================================
  // KPI 7: Enabling Autonomous Operations at Scale
  // Intelligence Agents reason about system state and take automated actions.
  // =========================================================================
  const AGENT_COUNT = randInt(AGENT_ACTION_MIN, AGENT_ACTION_MAX);
  const agentTimes = distribute(startPlus(start, 2), endMinus(now, 2), AGENT_COUNT, 0.08);

  for (let i = 0; i < agentTimes.length; i++) {
    const ts = agentTimes[i];
    const cluster = chooseWeighted(CLUSTERS, CLUSTER_WEIGHTS);
    const actionType = chooseWeighted(AGENT_ACTIONS, AGENT_ACTION_WEIGHTS);
    const isSuccess = Math.random() < AGENT_SUCCESS_RATE;

    events.push(makeEvent(EVENT_PROVIDER, "intelligence.agent.action", ts, {
      "action.id": "ACT-" + cryptoRandomId(8),
      "action.type": actionType,
      "action.outcome": isSuccess ? "success" : "failed",
      "cluster": cluster,
      "governance.approved": true,
      "governance.policy": choose(["auto-scale-policy", "incident-response", "cost-optimization", "security-enforcement"]),
      "affected.resources": randInt(1, 12),
      "execution.time.seconds": randInt(2, 120),
      "k8s.namespace": choose(NAMESPACES),
      ...(isSuccess ? {} : { "failure.reason": choose(["GOVERNANCE_BLOCKED", "RESOURCE_CONFLICT", "TIMEOUT", "DEPENDENCY_UNAVAILABLE"]) })
    }, now));
  }

  // ---------- Ingest (chunked, using integrated auth) ----------
  const totals = countBy(events, e => e["event.type"]);
  const batches = [];
  for (let i = 0; i < events.length; i += CHUNK) {
    const batch = events.slice(i, i + CHUNK);
    const res = await fetch("/platform/classic/environment-api/v2/bizevents/ingest", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(batch)
    });

    let text = "";
    try { text = await res.text(); } catch (e) {}

    if (!res.ok) {
      console.error(`BizEvents ingest failed for batch ${i}-${i + batch.length - 1}: HTTP ${res.status} ${text}`);
      throw new Error(`BizEvents ingest failed: HTTP ${res.status}`);
    }

    batches.push({ range: i + "-" + (i + batch.length - 1), status: res.status, bodyPreview: text.slice(0, 500) });
  }

  // Return summary to Workflow logs/output
  return {
    totals,
    batches,
    sample: events.slice(0, 3),
    meta: {
      totalEvents: events.length,
      gpuNodes: GPU_NODE_COUNT,
      llmInferences: LLM_COUNT,
      anomalies: ANOMALY_COUNT,
      cloudSignals: CLOUD_COUNT,
      securityScans: SCAN_COUNT,
      vulnerabilities: VULN_COUNT,
      agentActions: AGENT_COUNT,
      windowHours: HOURS_WINDOW
    }
  };
}
